function ContextMap(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"0 -24px",opacity:v?1:0,transition:"opacity 1s ease 0.15s"}}><svg viewBox="0 0 720 360" style={{width:"100%",display:"block"}}><defs><radialGradient id="pg" cx="360" cy="180" r="160" gradientUnits="userSpaceOnUse"><stop offset="0%" stopColor={C.terracotta} stopOpacity="0.06"/><stop offset="100%" stopColor={C.dark} stopOpacity="0"/></radialGradient></defs><rect width="720" height="360" fill={C.darkMid}/><path d="M50,20 Q200,30 360,25 Q520,20 680,40 L700,340 Q520,350 360,345 Q200,350 30,340 Z" fill={C.sage} fillOpacity="0.02" stroke={C.sage} strokeOpacity="0.06" strokeWidth="1" strokeDasharray="6,4"/><text x="620" y="50" fontFamily="Inter" fontSize="6.5" fill={C.sage} fillOpacity="0.3" textAnchor="end">AONB · DORSET</text><path d="M360,0 Q355,90 350,180 Q340,270 330,360" stroke={C.clay} strokeOpacity="0.08" strokeWidth="4" fill="none"/><text x="370" y="310" fontFamily="Inter" fontSize="6" fill={C.clay} fillOpacity="0.25">River Piddle ↓</text><path d="M340,0 Q342,90 345,180 Q348,270 350,360" stroke={C.warmGrey} strokeOpacity="0.1" strokeWidth="2" fill="none"/><circle cx="360" cy="180" r="120" fill="url(#pg)"/><circle cx="360" cy="180" r="5" fill={C.terracotta} fillOpacity="0.8"/><circle cx="360" cy="180" r="10" fill="none" stroke={C.terracotta} strokeOpacity="0.2" strokeWidth="1"/><text x="360" y="168" textAnchor="middle" fontFamily="Playfair Display" fontSize="9" fill={C.paper} fillOpacity="0.75" fontStyle="italic">Cherry Cottage</text><text x="360" y="200" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.35">Alton Pancras · 380 people</text>{[{x:360,y:90,l:"Buckland Newton",s:"1.5mi · village store · pub",c:C.sage},{x:360,y:270,l:"Piddletrenthide",s:"1.5mi · post office · school",c:C.sage},{x:140,y:300,l:"Dorchester",s:"10mi · Waterloo line",c:C.clay},{x:580,y:60,l:"Sherborne",s:"10mi · Waterloo line",c:C.clay},{x:100,y:180,l:"Heritage Coast",s:"~15mi",c:C.tertGrey}].map((p,i)=>(<g key={i}><circle cx={p.x} cy={p.y} r="2.5" fill={p.c} fillOpacity="0.5"/><line x1={p.x} y1={p.y-3} x2={p.x} y2={p.y-12} stroke={p.c} strokeOpacity="0.2" strokeWidth="1"/><text x={p.x} y={p.y-16} textAnchor="middle" fontFamily="Inter" fontSize="7.5" fill={p.c} fillOpacity="0.6" fontWeight="500">{p.l}</text><text x={p.x} y={p.y-7} textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.warmGrey} fillOpacity="0.3">{p.s}</text></g>))}<circle cx="360" cy="180" r="50" fill="none" stroke={C.warmGrey} strokeOpacity="0.04" strokeWidth="1" strokeDasharray="3,3"/><circle cx="360" cy="180" r="100" fill="none" stroke={C.warmGrey} strokeOpacity="0.03" strokeWidth="1" strokeDasharray="3,3"/><text x="698" y="16" textAnchor="end" fontFamily="Bebas Neue" fontSize="9" fill={C.warmGrey} fillOpacity="0.22">N ↑</text></svg></div>);}

function CrossSection(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"28px 0",opacity:v?1:0,transition:"all 0.8s ease 0.2s"}}><Lab color={C.clay}>CROSS SECTION · WHAT THE BUILDING IS MADE OF</Lab><svg viewBox="0 0 680 250" style={{width:"100%",display:"block",marginTop:"6px"}}><rect width="680" height="250" fill={C.darkCard} rx="4"/><line x1="0" y1="170" x2="680" y2="170" stroke={C.sage} strokeOpacity="0.15" strokeWidth="1"/><path d="M0,173 L680,173 L680,250 L0,250 Z" fill={C.sage} fillOpacity="0.02"/><rect x="120" y="80" width="260" height="90" fill="none" stroke={C.paper} strokeOpacity="0.2" strokeWidth="2"/><line x1="120" y1="195" x2="135" y2="195" stroke={C.clay} strokeOpacity="0.3" strokeWidth="1"/><text x="128" y="208" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.clay} fillOpacity="0.4">~18" walls</text><path d="M100,80 Q130,28 250,20 Q370,28 400,80" fill="none" stroke={C.clay} strokeOpacity="0.25" strokeWidth="2"/><path d="M105,80 Q130,32 250,24 Q370,32 395,80" fill="none" stroke={C.clay} strokeOpacity="0.1" strokeWidth="8"/><line x1="405" y1="50" x2="420" y2="50" stroke={C.terracotta} strokeOpacity="0.3" strokeWidth="1"/><line x1="405" y1="80" x2="420" y2="80" stroke={C.terracotta} strokeOpacity="0.3" strokeWidth="1"/><line x1="420" y1="50" x2="420" y2="80" stroke={C.terracotta} strokeOpacity="0.2" strokeWidth="0.5"/><text x="435" y="68" fontFamily="Bebas Neue" fontSize="8" fill={C.terracotta} fillOpacity="0.6">~12" THATCH</text><text x="435" y="78" fontFamily="Inter" fontSize="5.5" fill={C.warmGrey} fillOpacity="0.3">long straw · 20-30yr life</text><rect x="200" y="10" width="25" height="70" fill="none" stroke={C.paper} strokeOpacity="0.12" strokeWidth="1.5"/><text x="212" y="5" textAnchor="middle" fontFamily="Inter" fontSize="5" fill={C.warmGrey} fillOpacity="0.3">chimney</text><rect x="195" y="110" width="35" height="60" fill="none" stroke={C.terracotta} strokeOpacity="0.1" strokeWidth="1" strokeDasharray="3,2"/><text x="212" y="145" textAnchor="middle" fontFamily="Inter" fontSize="5" fill={C.terracotta} fillOpacity="0.35">inglenook</text>{[160,220,280,340].map((x,i)=>(<rect key={i} x={x} y="78" width="8" height="4" fill={C.clay} fillOpacity="0.15" rx="1"/>))}<text x="250" y="76" textAnchor="middle" fontFamily="Inter" fontSize="5" fill={C.clay} fillOpacity="0.3">exposed beams</text><text x="170" y="130" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.clay} fillOpacity="0.6">Entrance</text><text x="310" y="130" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.clay} fillOpacity="0.6">Panelled Room</text><text x="250" y="55" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.3">bedrooms follow roof pitch</text><rect x="380" y="100" width="140" height="70" fill="none" stroke={C.warmGrey} strokeOpacity="0.08" strokeWidth="1" strokeDasharray="4,2"/><path d="M380,100 L450,90 L520,100" fill="none" stroke={C.warmGrey} strokeOpacity="0.08" strokeWidth="1"/><text x="450" y="140" textAnchor="middle" fontFamily="Inter" fontSize="7" fill={C.warmGrey} fillOpacity="0.25">extension</text><text x="450" y="150" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.warmGrey} fillOpacity="0.2">~1960s · different construction</text><text x="128" y="175" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.terracotta} fillOpacity="0.4">no DPC</text><text x="340" y="235" textAnchor="middle" fontFamily="Inter" fontSize="7" fill={C.warmGrey} fillOpacity="0.25">17th/18th century cob/stone · thatched · Grade II Listed</text></svg></div>);}

function FloorPlans(){const[ref,v]=useReveal();const wall=`${C.paper}25`;const wallW="1.5";const annoC=`${C.warmGrey}60`;return(<div ref={ref} style={{margin:"28px 0",opacity:v?1:0,transition:"opacity 0.8s ease 0.2s"}}><Lab color={C.clay}>FLOOR PLANS · ARCHITECT'S READING</Lab><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"8px"}}><div style={{background:C.darkCard,borderRadius:"4px",padding:"12px"}}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:C.clay,letterSpacing:"0.08em",marginBottom:"8px"}}>GROUND FLOOR</div><svg viewBox="0 0 280 220" style={{width:"100%",display:"block"}}><rect x="20" y="20" width="160" height="140" fill="none" stroke={wall} strokeWidth="3"/><rect x="180" y="40" width="80" height="120" fill="none" stroke={wall} strokeWidth="1.5" strokeDasharray="4,2"/><line x1="100" y1="20" x2="100" y2="160" stroke={wall} strokeWidth="1.5"/><rect x="85" y="20" width="30" height="15" fill={C.clay} fillOpacity="0.06" stroke={wall} strokeWidth="1"/><text x="60" y="85" textAnchor="middle" fontFamily="Playfair Display" fontSize="9" fill={C.clay} fillOpacity="0.7">Entrance</text><text x="60" y="97" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={annoC}>inglenook · flagstone</text><text x="140" y="85" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.clay} fillOpacity="0.7">Panelled</text><text x="140" y="97" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.clay} fillOpacity="0.7">Room</text><text x="140" y="109" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.terracotta} fillOpacity="0.5">Georgian · damp</text><text x="220" y="85" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.warmGrey} fillOpacity="0.5">Kitchen</text><text x="220" y="97" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={annoC}>AGA · beams</text><line x1="100" y1="160" x2="140" y2="160" stroke={C.darkCard} strokeWidth="4"/><text x="120" y="175" textAnchor="middle" fontFamily="Inter" fontSize="5" fill={C.sage} fillOpacity="0.4">→ garden</text>{[[20,50,20,80],[20,110,20,140],[80,20,120,20],[150,160,170,160]].map(([x1,y1,x2,y2],i)=>(<line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={C.clay} strokeWidth="1.5" strokeOpacity="0.3"/>))}<g transform="translate(250,200)"><circle r="10" fill="none" stroke={C.warmGrey} strokeOpacity="0.12" strokeWidth="0.5"/><line x1="0" y1="7" x2="0" y2="-7" stroke={C.warmGrey} strokeOpacity="0.25" strokeWidth="0.7"/><text y="-10" textAnchor="middle" fontFamily="Bebas Neue" fontSize="6" fill={C.warmGrey} fillOpacity="0.3">N</text></g></svg></div><div style={{background:C.darkCard,borderRadius:"4px",padding:"12px"}}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:C.clay,letterSpacing:"0.08em",marginBottom:"8px"}}>FIRST FLOOR</div><svg viewBox="0 0 280 220" style={{width:"100%",display:"block"}}><rect x="20" y="40" width="160" height="120" fill="none" stroke={wall} strokeWidth="2"/><line x1="100" y1="40" x2="100" y2="160" stroke={wall} strokeWidth="1"/><text x="60" y="95" textAnchor="middle" fontFamily="Playfair Display" fontSize="10" fill={C.clay} fillOpacity="0.7">Bed 1</text><text x="60" y="108" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={annoC}>under thatch · low eaves</text><text x="60" y="118" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.terracotta} fillOpacity="0.4">electric heater only</text><text x="145" y="95" textAnchor="middle" fontFamily="Playfair Display" fontSize="10" fill={C.clay} fillOpacity="0.7">Bed 2</text><text x="145" y="108" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={annoC}>small casement</text><rect x="180" y="60" width="60" height="50" fill="none" stroke={wall} strokeWidth="1" strokeDasharray="3,2"/><text x="210" y="90" textAnchor="middle" fontFamily="Playfair Display" fontSize="8" fill={C.warmGrey} fillOpacity="0.5">Bath</text><rect x="85" y="40" width="15" height="12" fill={C.clay} fillOpacity="0.06" stroke={wall} strokeWidth="0.8"/><text x="100" y="180" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.3">ceiling follows thatch pitch · headroom limited at eaves</text></svg></div></div></div>);}

function StreetElevation(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"28px 0",opacity:v?1:0,transition:"opacity 0.8s ease 0.2s"}}><Lab color={C.sage}>STREET ELEVATION · FROM THE VALLEY ROAD</Lab><svg viewBox="0 0 680 200" style={{width:"100%",display:"block",marginTop:"6px"}}><rect width="680" height="200" fill={C.darkCard} rx="4"/><line x1="0" y1="155" x2="680" y2="155" stroke={C.sage} strokeOpacity="0.12" strokeWidth="1"/><path d="M0,158 L680,158 L680,200 L0,200 Z" fill={C.sage} fillOpacity="0.02"/><rect x="200" y="100" width="160" height="55" fill="none" stroke={C.paper} strokeOpacity="0.2" strokeWidth="1.5"/><path d="M185,100 Q210,45 280,38 Q350,45 375,100" fill="none" stroke={C.clay} strokeOpacity="0.2" strokeWidth="2"/><path d="M188,100 Q212,48 280,42 Q348,48 372,100" fill="none" stroke={C.clay} strokeOpacity="0.08" strokeWidth="6"/><rect x="265" y="25" width="18" height="40" fill="none" stroke={C.paper} strokeOpacity="0.12" strokeWidth="1"/><rect x="220" y="115" width="15" height="20" fill="none" stroke={C.clay} strokeOpacity="0.15" strokeWidth="1"/><rect x="250" y="115" width="15" height="20" fill="none" stroke={C.clay} strokeOpacity="0.15" strokeWidth="1"/><rect x="310" y="110" width="12" height="45" fill="none" stroke={C.sage} strokeOpacity="0.2" strokeWidth="1"/><rect x="360" y="108" width="100" height="47" fill="none" stroke={C.warmGrey} strokeOpacity="0.07" strokeWidth="1"/><path d="M360,108 L410,95 L460,108" fill="none" stroke={C.warmGrey} strokeOpacity="0.07" strokeWidth="1"/><text x="410" y="135" textAnchor="middle" fontFamily="Inter" fontSize="5" fill={C.warmGrey} fillOpacity="0.2">extension</text><path d="M185,100 L155,125 L155,155 L185,155" fill="none" stroke={C.warmGrey} strokeOpacity="0.06" strokeWidth="1"/>{[130,490,540].map((x,i)=>(<circle key={i} cx={x} cy={100+i*15} r={18+i*4} fill={C.sage} fillOpacity="0.03" stroke={C.sage} strokeOpacity="0.05" strokeWidth="1"/>))}<line x1="280" y1="32" x2="280" y2="18" stroke={C.terracotta} strokeOpacity="0.25" strokeWidth="1"/><text x="280" y="14" textAnchor="middle" fontFamily="Playfair Display" fontSize="9" fill={C.terracotta} fillOpacity="0.65" fontStyle="italic">Cherry Cottage</text><text x="340" y="185" textAnchor="middle" fontFamily="Inter" fontSize="6.5" fill={C.warmGrey} fillOpacity="0.25">Grade II · thatched · rendered cob/stone · Piddle Valley</text></svg></div>);}

function SunStudy(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"28px 0",opacity:v?1:0,transition:"opacity 0.8s ease 0.2s"}}><Lab color={C.clay}>LIGHT STUDY · SMALL WINDOWS, THICK WALLS</Lab><svg viewBox="0 0 680 220" style={{width:"100%",display:"block",marginTop:"6px"}}><rect width="680" height="220" fill={C.darkCard} rx="4"/><rect x="250" y="70" width="120" height="80" fill="none" stroke={C.paper} strokeOpacity="0.12" strokeWidth="1.5"/><rect x="370" y="80" width="70" height="60" fill="none" stroke={C.warmGrey} strokeOpacity="0.06" strokeWidth="1" strokeDasharray="3,2"/><text x="290" y="100" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.35">Entrance</text><text x="340" y="100" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.35">Panelled</text><text x="405" y="100" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.warmGrey} fillOpacity="0.25">Kitchen</text><path d="M60,180 Q160,20 340,10 Q520,20 620,180" fill="none" stroke={C.clay} strokeOpacity="0.12" strokeWidth="1" strokeDasharray="4,3"/><circle cx="100" cy="140" r="12" fill={C.clay} fillOpacity="0.05" stroke={C.clay} strokeOpacity="0.12" strokeWidth="1"/><text x="100" y="143" textAnchor="middle" fontFamily="Bebas Neue" fontSize="8" fill={C.clay} fillOpacity="0.45">AM</text>{[90,100,110].map((y,i)=>(<line key={`a${i}`} x1="118" y1={y+15} x2="248" y2={y-10} stroke={C.clay} strokeOpacity={0.03+i*0.012} strokeWidth="5"/>))}<text x="180" y="80" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.clay} fillOpacity="0.35">small windows limit morning light</text><circle cx="340" cy="25" r="12" fill={C.clay} fillOpacity="0.06" stroke={C.clay} strokeOpacity="0.15" strokeWidth="1"/><text x="340" y="28" textAnchor="middle" fontFamily="Bebas Neue" fontSize="8" fill={C.clay} fillOpacity="0.5">12</text><circle cx="580" cy="140" r="12" fill={C.clay} fillOpacity="0.05" stroke={C.clay} strokeOpacity="0.12" strokeWidth="1"/><text x="580" y="143" textAnchor="middle" fontFamily="Bebas Neue" fontSize="8" fill={C.clay} fillOpacity="0.45">PM</text>{[90,105,120].map((y,i)=>(<line key={`p${i}`} x1="565" y1={y} x2="442" y2={y+8} stroke={C.clay} strokeOpacity={0.03+i*0.012} strokeWidth="5"/>))}<text x="500" y="155" textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.clay} fillOpacity="0.35">afternoon into garden</text><text x="340" y="170" textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.sage} fillOpacity="0.3">garden · 0.2 acres · woodland beyond</text><text x="340" y="208" textAnchor="middle" fontFamily="EB Garamond" fontSize="9.5" fill={C.accent} fillOpacity="0.55" fontStyle="italic">Deep-set windows. Thick walls. The cottage holds its warmth but surrenders light reluctantly.</text></svg></div>);}

function ThatchLifecycle(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"28px 0",opacity:v?1:0,transition:"opacity 0.8s ease 0.2s"}}><Lab color={C.terracotta}>THATCH LIFECYCLE · THE ROOF IS A COMMITMENT</Lab><svg viewBox="0 0 680 140" style={{width:"100%",display:"block",marginTop:"6px"}}><rect width="680" height="140" fill={C.darkCard} rx="4"/><line x1="40" y1="70" x2="640" y2="70" stroke={C.warmGrey} strokeOpacity="0.1" strokeWidth="1"/>{[0,5,10,15,20,25,30].map((yr,i)=>{const x=40+i*100;return(<g key={i}><line x1={x} y1="65" x2={x} y2="75" stroke={C.warmGrey} strokeOpacity="0.15" strokeWidth="1"/><text x={x} y="88" textAnchor="middle" fontFamily="Bebas Neue" fontSize="9" fill={C.warmGrey} fillOpacity="0.35">YR {yr}</text></g>);})}{[10,20].map((yr,i)=>{const x=40+(yr/30)*600;return(<g key={`r${i}`}><circle cx={x} cy={70} r={v?6:0} fill={C.clay} fillOpacity="0.3" style={{transition:`all 0.4s ease ${0.2+i*0.1}s`}}/><text x={x} y={55} textAnchor="middle" fontFamily="Inter" fontSize="6" fill={C.clay} fillOpacity="0.5">RIDGE</text><text x={x} y="105" textAnchor="middle" fontFamily="Bebas Neue" fontSize="8" fill={C.clay} fillOpacity="0.5">£3–5K</text></g>);})}<g><circle cx={580} cy={70} r={v?9:0} fill={C.terracotta} fillOpacity="0.4" style={{transition:"all 0.5s ease 0.4s"}}/><text x={580} y={50} textAnchor="middle" fontFamily="Inter" fontSize="7" fill={C.terracotta} fillOpacity="0.6" fontWeight="500">RE-THATCH</text><text x={580} y="105" textAnchor="middle" fontFamily="Bebas Neue" fontSize="10" fill={C.terracotta} fillOpacity="0.7">£15–25K</text></g><text x="340" y="125" textAnchor="middle" fontFamily="Inter" fontSize="6.5" fill={C.warmGrey} fillOpacity="0.3">Annual inspection + netting: ~£300–500/yr</text></svg></div>);}

function ConditionMatrix(){const[ref,v]=useReveal();const items=[{a:"Thatch",n:"Age unknown — survey essential",r:3},{a:"Panelling / damp",n:"Visible staining — investigate",r:3},{a:"Heating",n:"None. Electric heaters only",r:3},{a:"Electrics",n:"Age unknown — test required",r:2},{a:"Drainage",n:"Mains connected — good",r:1},{a:"Extension",n:"Structure unknown — assess",r:2}];return(<div ref={ref} style={{margin:"24px 0",opacity:v?1:0,transition:"opacity 0.6s ease 0.1s"}}><Lab color={C.terracotta}>CONDITION · WHAT THE PHOTOS TELL US</Lab><div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:"4px"}}>{items.map((item,i)=>(<div key={i} style={{background:C.darkCard,borderRadius:"3px",padding:"9px 10px",borderLeft:`2px solid ${item.r===3?C.terracotta:item.r===2?C.clay:C.sage}`,opacity:v?1:0,transition:`opacity 0.35s ease ${0.08+i*0.04}s`}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"1px"}}><span style={{fontFamily:"'Playfair Display',serif",fontSize:"11px",color:C.paper}}>{item.a}</span><div style={{display:"flex",gap:"2px"}}>{[1,2,3].map(r=>(<div key={r} style={{width:"4px",height:"4px",borderRadius:"50%",background:r<=item.r?(item.r===3?C.terracotta:item.r===2?C.clay:C.sage):C.darkMid}}/>))}</div></div><div style={{fontFamily:"'Inter',sans-serif",fontSize:"8.5px",color:C.warmGrey}}>{item.n}</div></div>))}</div></div>);}

function PriceGap(){const[ref,v]=useReveal();return(<div ref={ref} style={{margin:"24px 0",opacity:v?1:0,transition:"opacity 0.7s ease 0.1s"}}><Lab color={C.clay}>PRICE CONTEXT · THATCHED COTTAGES IN DORSET AONB</Lab><svg viewBox="0 0 680 110" style={{width:"100%",display:"block",marginTop:"6px"}}><rect width="680" height="110" fill={C.darkCard} rx="4"/><line x1="45" y1="52" x2="635" y2="52" stroke={C.warmGrey} strokeOpacity="0.08" strokeWidth="1"/><defs><marker id="ar" markerWidth="5" markerHeight="4" refX="5" refY="2" orient="auto"><path d="M0,0 L5,2 L0,4" fill={C.clay} fillOpacity="0.3"/></marker></defs>{[{x:120,p:"£200K",l:"THIS",s:"guide",c:C.terracotta,r:7},{x:320,p:"£350–400K",l:"Renovated cottage",s:"Piddle Valley",c:C.clay,r:5},{x:520,p:"£500–600K",l:"Comparable done well",s:"AONB Dorset",c:C.sage,r:4}].map((p,i)=>(<g key={i}><circle cx={p.x} cy={52} r={v?p.r:0} fill={p.c} fillOpacity={i===0?0.75:0.25} style={{transition:`all 0.45s ease ${0.2+i*0.08}s`}}/><text x={p.x} y={36} textAnchor="middle" fontFamily="Bebas Neue" fontSize={i===0?"14":"10"} fill={p.c}>{p.p}</text><text x={p.x} y={72} textAnchor="middle" fontFamily="Inter" fontSize="6.5" fill={C.warmGrey} fillOpacity="0.4">{p.l}</text><text x={p.x} y={82} textAnchor="middle" fontFamily="Inter" fontSize="5.5" fill={C.tertGrey} fillOpacity="0.3">{p.s}</text></g>))}<line x1="133" y1="43" x2="505" y2="43" stroke={C.clay} strokeOpacity="0.15" strokeWidth="1" markerEnd="url(#ar)"/><text x="320" y="38" textAnchor="middle" fontFamily="Bebas Neue" fontSize="9" fill={C.clay} fillOpacity="0.4">£150–400K POTENTIAL UPSIDE</text></svg></div>);}

function BudgetBars(){const[ref,v]=useReveal();const items=[{l:"Thatch survey + repair",lo:5,hi:25,c:C.terracotta},{l:"Heating system",lo:8,hi:15,c:C.terracotta},{l:"Damp investigation",lo:3,hi:10,c:C.terracotta},{l:"Rewire",lo:5,hi:10,c:C.clay},{l:"Kitchen",lo:8,hi:20,c:C.clay},{l:"Bathroom",lo:5,hi:12,c:C.clay},{l:"LBC fees + architect",lo:3,hi:8,c:C.fee},{l:"Contingency",lo:10,hi:20,c:C.fee}];const mx=Math.max(...items.map(i=>i.hi));const tl=items.reduce((a,b)=>a+b.lo,0);const th=items.reduce((a,b)=>a+b.hi,0);return(<div ref={ref} style={{margin:"24px 0",opacity:v?1:0,transition:"opacity 0.7s ease 0.1s"}}><Lab color={C.accentDark}>REMEDIAL BUDGET</Lab><div style={{display:"flex",flexDirection:"column",gap:"3px"}}>{items.map((it,i)=>(<div key={i} style={{display:"flex",alignItems:"center",gap:"7px"}}><div style={{width:"110px",textAlign:"right",fontFamily:"'Inter',sans-serif",fontSize:"9px",color:C.warmGrey,flexShrink:0}}>{it.l}</div><div style={{flex:1,position:"relative",height:"14px"}}><div style={{position:"absolute",left:0,top:"2px",height:"10px",width:v?`${(it.lo/mx)*100}%`:"0%",background:it.c,opacity:0.32,borderRadius:"1.5px",transition:`width 0.6s ease ${0.1+i*0.05}s`}}/><div style={{position:"absolute",left:0,top:"2px",height:"10px",width:v?`${(it.hi/mx)*100}%`:"0%",background:it.c,opacity:0.1,borderRadius:"1.5px",transition:`width 0.8s ease ${0.1+i*0.05}s`}}/></div><div style={{width:"52px",fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:it.c,flexShrink:0}}>£{it.lo}–{it.hi}K</div></div>))}</div><div style={{textAlign:"right",marginTop:"10px"}}><div style={{fontFamily:"'Playfair Display',serif",fontSize:"clamp(20px,3.5vw,28px)",color:C.accentDark}}>£{tl}K – £{th}K</div><Cap>essential works · before the extension question</Cap></div></div>);}

function Scenarios(){const[ref,v]=useReveal();return(<div ref={ref} style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"6px",margin:"24px 0",opacity:v?1:0,transition:"opacity 0.7s ease 0.1s"}}>{[{t:"Best case",s:"Thatch sound, damp cosmetic",cost:"£340K",up:"£200K+ upside",c:C.sage,items:["Thatch has 10+ yrs left","Damp is surface condensation","Heat + cosmetic only"]},{t:"Worst case",s:"Full restoration",cost:"£430K+",up:"Upside depends on craft",c:C.terracotta,items:["Full re-thatch needed","Structural damp behind panelling","Full rewire + heating"]}].map((s,i)=>(<div key={i} style={{background:C.darkCard,borderRadius:"3px",padding:"13px",borderTop:`2px solid ${s.c}`}}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"11px",color:s.c,letterSpacing:"0.06em"}}>{s.t}</div><Cap style={{marginBottom:"7px"}}>{s.s}</Cap><div style={{fontFamily:"'Playfair Display',serif",fontSize:"20px",color:C.paper,marginBottom:"2px"}}>{s.cost}</div><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:s.c,marginBottom:"8px"}}>{s.up}</div>{s.items.map((item,j)=>(<div key={j} style={{display:"flex",alignItems:"center",gap:"5px",marginBottom:"3px"}}><div style={{width:"3px",height:"3px",borderRadius:"50%",background:s.c,opacity:0.4,flexShrink:0}}/><span style={{fontFamily:"'Inter',sans-serif",fontSize:"8px",color:C.warmGrey}}>{item}</span></div>))}</div>))}</div>);}

function MaterialPalette(){const[ref,v]=useReveal();const mats=[{n:"Long straw thatch",c:"£15–25K re-thatch",src:IMG_MAT1},{n:"Lime plaster",c:"£35–50/m²",src:IMG_MAT2},{n:"Flagstone",c:"£60–90/m²",src:IMG_MAT3},{n:"Green oak",c:"£800–1.5K/m²",src:IMG_MAT4}];return(<div ref={ref} style={{margin:"24px 0",opacity:v?1:0,transition:"opacity 0.7s ease 0.12s"}}><Lab color={C.clay}>MATERIALS · WHAT A LISTED COTTAGE DEMANDS</Lab><div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:"4px"}}>{mats.map((m,i)=>(<div key={i} style={{aspectRatio:"1",borderRadius:"3px",overflow:"hidden",position:"relative",opacity:v?1:0,transition:`opacity 0.4s ease ${0.12+i*0.07}s`}}><img src={m.src} style={{width:"100%",height:"100%",objectFit:"cover"}} alt="" /><div style={{position:"absolute",bottom:0,left:0,right:0,padding:"18px 6px 6px",background:"linear-gradient(transparent, rgba(26,24,22,0.85))"}}><div style={{fontFamily:"'Playfair Display',serif",fontSize:"9.5px",color:C.paper}}>{m.n}</div><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"8px",color:C.clay}}>{m.c}</div></div></div>))}</div></div>);}

/* ═══ MAIN REPORT ═══ */
export default function PiegaReportCherry() {
  const [loaded, setLoaded] = useState(false);
  useEffect(() => { setTimeout(() => setLoaded(true), 100); }, []);
  return (
    <div style={{ background: C.dark, minHeight: "100vh", color: C.paper, overflowX: "hidden" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&family=EB+Garamond:ital@0;1&family=Bebas+Neue&family=Inter:wght@300;400;500&display=swap');
        * { box-sizing: border-box; }
        ::selection { background: ${C.terracotta}; color: ${C.paper}; }
        html { scroll-behavior: smooth; }
      `}</style>
      <div style={{ maxWidth: "680px", margin: "0 auto", padding: "0 24px" }}>
        <div style={{ padding: "20px 0 0", fontFamily: "'Playfair Display',serif", fontSize: "14px", color: C.accentDark, opacity: loaded ? 1 : 0, transition: "opacity 1s ease 0.2s" }}>Piega</div>

        {/* HERO */}
        <div style={{ padding: "48px 0 0" }}>
          <Reveal><Lab color={C.terracotta}>AUCTION · DIGBY HALL, SHERBORNE</Lab></Reveal>
          <Reveal delay={0.08}><h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: "clamp(34px,6.5vw,48px)", fontWeight: 400, lineHeight: 1.08, color: C.paper, margin: "0 0 6px" }}>Cherry Cottage</h1></Reveal>
          <Reveal delay={0.13}><Cap style={{ fontSize: "12px", color: C.warmGrey }}>Alton Pancras, Dorchester, Dorset, DT2 7RW · 2 bed · Detached · Thatched · Freehold</Cap></Reveal>
          <Reveal delay={0.2}>
            <div style={{ display: "flex", gap: "16px", margin: "24px 0 0", flexWrap: "wrap" }}>
              {[{v:"£200K",s:"guide"},{v:"GRADE II",s:"listed"},{v:"2 BED",s:"+ extension"},{v:"0.2 ACRE",s:"garden + woodland"},{v:"10 MI",s:"to Dorchester"}].map((s,i)=>(
                <div key={i}><div style={{fontFamily:"'Bebas Neue',sans-serif",fontSize:"clamp(17px,2.8vw,22px)",color:i===0?C.accentDark:i===1?C.terracotta:C.paper}}>{s.v}</div><Cap>{s.s}</Cap></div>
              ))}
            </div>
          </Reveal>
        </div>

        {/* THE APPROACH */}
        <Reveal style={{marginTop:"36px"}}>
          <Photo src={IMG_SLOT1} aspect="2.2/1" tag="THE APPROACH · FROM THE LANE" />
        </Reveal>
        <Reveal>
          <Verse>Three hundred and eighty people live in this valley. None of them are in a hurry. The cottage has been here since before the road was metalled. It does not know the meaning of the word modernisation. The estate agent does.</Verse>
        </Reveal>

        {/* THE PLACE */}
        <Reveal><ContextMap /></Reveal>
        <Reveal><StreetElevation /></Reveal>
        <Reveal>
          <Verse style={{ fontSize: "clamp(13px,2vw,16px)", color: C.warmGrey }}>
            Alton Pancras. Population: 380. Pubs: 0. Post office: 0. The nearest pint is 1.5 miles north at The Gaggle of Geese.
            <span style={{ display: "block", marginTop: "10px", fontStyle: "normal", fontFamily: "'Bebas Neue',sans-serif", fontSize: "clamp(13px,2vw,16px)", color: C.terracotta, letterSpacing: "0.04em", textTransform: "uppercase" }}>This is a life you have to mean.</span>
          </Verse>
        </Reveal>

        {/* THE ENTRANCE */}
        <Reveal><Slab>The front door.</Slab></Reveal>
        <Reveal><Photo src={IMG_SLOT2} aspect="3/4" tag="ENTRANCE · INGLENOOK · FLAGSTONE" style={{maxWidth:"440px"}} /></Reveal>
        <Reveal><Verse>The flagstones are cold underfoot. The beam above your head has held this ceiling for three centuries. The inglenook is the kind of fireplace that makes a room unnecessary — it is the room.</Verse></Reveal>

        <Reveal><FloorPlans /></Reveal>
        <Reveal><CrossSection /></Reveal>
        <Reveal><SunStudy /></Reveal>

        {/* THE PANELLED ROOM */}
        <Reveal><Slab>The room that matters.</Slab></Reveal>
        <Reveal><Photo src={IMG_SLOT3} aspect="16/9" tag="PANELLED ROOM · GEORGIAN · DAMP VISIBLE" /></Reveal>
        <Reveal>
          <Verse>The panelling is Georgian. The damp behind it is older. You are buying both.
            <span style={{ display: "block", marginTop: "10px", fontStyle: "normal", fontFamily: "'Inter',sans-serif", fontSize: "10px", color: C.tertGrey }}>Listed Building Consent required for any repair to the panelling.</span>
          </Verse>
        </Reveal>
        <Reveal>
          <BeforeAfterReal label="DRAG · THE PANELLED ROOM" beforeSrc={IMG_SLOT3} afterSrc={IMG_SLOT4B} />
        </Reveal>

        {/* THE AGA KITCHEN */}
        <Reveal><Slab>The room someone actually lived in.</Slab></Reveal>
        <Reveal>
          <BeforeAfterReal label="DRAG · THE AGA KITCHEN" beforeSrc={IMG_BEFORE_AGA} afterSrc={IMG_SLOT7} />
        </Reveal>
        <Reveal>
          <Verse>The AGA is the argument for the ground floor. It has been heating this room since before central heating was a phrase anyone used.
            <span style={{ display: "block", marginTop: "8px", fontStyle: "normal", fontFamily: "'Inter',sans-serif", fontSize: "10px", color: C.tertGrey }}>The flagstones, the refectory table, the bread on the board — these are not staging. They are a way of living.</span>
          </Verse>
        </Reveal>

        {/* THE BEDROOM */}
        <Reveal><Slab>Upstairs. Under the thatch.</Slab></Reveal>
        <Reveal><Photo src={IMG_SLOT5} aspect="16/10" tag="BEDROOM · NO HEATING · UNDER THATCH" /></Reveal>
        <Reveal>
          <Verse>Someone put an electric heater on the floor of a seventeenth-century bedroom. That is not heating. That is hope.
            <span style={{ display: "block", marginTop: "10px", fontStyle: "normal", fontFamily: "'Bebas Neue',sans-serif", fontSize: "clamp(12px,1.8vw,15px)", color: C.terracotta, letterSpacing: "0.04em", textTransform: "uppercase" }}>Installing central heating in a listed building requires consent and about twelve thousand pounds.</span>
          </Verse>
        </Reveal>

        {/* THE GARDEN */}
        <Reveal><Photo src={IMG_SLOT6} aspect="16/9" tag="GARDEN · 0.2 ACRES · WOODLAND" /></Reveal>
        <Reveal><Verse>The garden is not a garden. It is 0.2 acres of possibility surrounded by trees that were here before the cottage was.</Verse></Reveal>

        <Reveal><MaterialPalette /></Reveal>

        {/* THE HONEST LAYER */}
        <Reveal><div style={{ width: "40px", height: "1px", background: C.accentDark, margin: "36px 0", opacity: 0.2 }} /></Reveal>
        <Reveal><Slab>Listed Grade II.<br/>Everything you want to change, you must first ask permission to change.</Slab></Reveal>

        <Reveal><ThatchLifecycle /></Reveal>
        <Reveal><ConditionMatrix /></Reveal>
        <Reveal>
          <Verse>The thatch is the building. When it fails, the walls get wet. When the walls get wet, the beams rot.
            <span style={{ display: "block", marginTop: "8px", fontStyle: "normal", fontFamily: "'Bebas Neue',sans-serif", fontSize: "clamp(12px,1.8vw,15px)", color: C.terracotta, letterSpacing: "0.04em", textTransform: "uppercase" }}>A thatch survey before auction is not optional.</span>
          </Verse>
        </Reveal>

        <Reveal><PriceGap /></Reveal>
        <Reveal><Scenarios /></Reveal>
        <Reveal><BudgetBars /></Reveal>

        {/* TOTAL */}
        <Reveal>
          <div style={{ background: C.darkCard, borderRadius: "4px", padding: "16px", margin: "24px 0" }}>
            {[{l:"Purchase (guide)",lo:200,hi:220,c:C.accentDark},{l:"Stamp + legal + premium",lo:8,hi:14,c:C.warmGrey},{l:"Essential works",lo:47,hi:120,c:C.terracotta}].map((l,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",marginBottom:"6px"}}><div style={{width:"140px",fontFamily:"'Inter',sans-serif",fontSize:"9px",color:C.warmGrey,flexShrink:0}}>{l.l}</div><div style={{flex:1}}><div style={{height:"3px",background:l.c,opacity:0.35,borderRadius:"2px",width:`${(l.hi/360)*100}%`,minWidth:"4px"}}/></div><div style={{width:"68px",textAlign:"right",fontFamily:"'Bebas Neue',sans-serif",fontSize:"10px",color:l.c,flexShrink:0}}>£{l.lo}–{l.hi}K</div></div>
            ))}
            <div style={{borderTop:`1px solid ${C.warmGrey}10`,marginTop:"8px",paddingTop:"8px",display:"flex",justifyContent:"space-between",alignItems:"baseline"}}>
              <Cap>Total envelope</Cap>
              <span style={{fontFamily:"'Playfair Display',serif",fontSize:"clamp(22px,4vw,32px)",color:C.paper}}>£255K – £354K</span>
            </div>
          </div>
        </Reveal>

        {/* FINAL */}
        <Reveal><Verse>A Grade II thatched cottage in an Area of Outstanding Natural Beauty for two hundred thousand pounds. The price is low because the work is high. The question is whether you are the kind of person the house has been waiting for.</Verse></Reveal>
        <Reveal><Verse style={{ color: C.warmGrey, fontSize: "clamp(13px,2vw,16px)" }}>The thatch has been here since before the bypass.<br/>It does not care about your timeline.</Verse></Reveal>

        <div style={{ width: "40px", height: "1px", background: C.accentDark, margin: "36px auto", opacity: 0.2 }} />

        {/* GATE */}
        <Reveal>
          <div style={{ textAlign: "center", padding: "14px 0 64px" }}>
            <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: "clamp(16px,2.8vw,20px)", color: C.paper, letterSpacing: "0.04em", textTransform: "uppercase", marginBottom: "6px" }}>You read this far.</div>
            <div style={{ fontFamily: "'Playfair Display',serif", fontSize: "13px", fontStyle: "italic", color: C.warmGrey, maxWidth: "340px", margin: "0 auto 20px", lineHeight: 1.5 }}>This is one building. Yours is different.</div>
            <div style={{ display: "flex", maxWidth: "320px", margin: "0 auto", gap: "6px" }}>
              <input type="email" placeholder="your@email.com" style={{ flex: 1, height: "38px", background: C.darkMid, border: `1px solid ${C.lightGrey}24`, borderRadius: "4px", color: C.paper, fontFamily: "'EB Garamond',serif", fontSize: "13px", padding: "0 12px", outline: "none" }} />
              <button style={{ height: "38px", padding: "0 14px", background: "transparent", border: `1px solid ${C.accentDark}`, borderRadius: "4px", color: C.accentDark, fontFamily: "'Bebas Neue',sans-serif", fontSize: "11px", letterSpacing: "0.08em", cursor: "pointer" }}>SEND IT</button>
            </div>
            <Cap style={{ marginTop: "36px", opacity: 0.28 }}>Not affiliated with any estate agent. That is the point.</Cap>
          </div>
        </Reveal>
      </div>
    </div>
  );
}
